# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

import redis
from flask import Flask, request, jsonify

app = Flask(__name__)

# Redis configuration
REDIS_HOSTS = ['redis-node1.example.com', 'redis-node2.example.com']
REDIS_PORT = 6379
REDIS_DB = 0
SESSION_TTL = 3600  # 1 hour in seconds
API_KEY_TTL = 86400  # 1 day in seconds

# Create Redis connection pool
pool = redis.ConnectionPool(host=REDIS_HOSTS, port=REDIS_PORT, db=REDIS_DB)
redis_client = redis.Redis(connection_pool=pool)

@app.route('/set_session', methods=['POST'])
def set_session():
    data = request.json
    session_token = data.get('session_token')
    user_id = data.get('user_id')

    if not session_token or not user_id:
        return jsonify({'error': 'Missing session token or user ID'}), 400

    redis_client.setex(session_token, SESSION_TTL, user_id)
    return jsonify({'message': 'Session token set successfully'}), 200

@app.route('/get_session', methods=['GET'])
def get_session():
    session_token = request.args.get('session_token')

    if not session_token:
        return jsonify({'error': 'Missing session token'}), 400

    user_id = redis_client.get(session_token)
    if user_id:
        return jsonify({'user_id': user_id.decode()}), 200
    else:
        return jsonify({'error': 'Session token not found'}), 404

@app.route('/set_api_key', methods=['POST'])
def set_api_key():
    data = request.json
    api_key = data.get('api_key')
    service_name = data.get('service_name')

    if not api_key or not service_name:
        return jsonify({'error': 'Missing API key or service name'}), 400

    redis_client.setex(api_key, API_KEY_TTL, service_name)
    return jsonify({'message': 'API key set successfully'}), 200

@app.route('/get_api_key', methods=['GET'])
def get_api_key():
    api_key = request.args.get('api_key')

    if not api_key:
        return jsonify({'error': 'Missing API key'}), 400

    service_name = redis_client.get(api_key)
    if service_name:
        return jsonify({'service_name': service_name.decode()}), 200
    else:
        return jsonify({'error': 'API key not found'}), 404

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)